const router = require("express").Router();
const Sale = require("../models/Sale");
const Vehicle = require("../models/Vehicle");

const auth = require("../middleware/auth");
const authorize = require("../middleware/authorize");
const { validateObjectId } = require("../utils/validateObjectId");

/**
 * ✅ STATS FIRST (must be above "/:id")
 * GET /api/sales/stats?year=2026
 */
router.get("/stats", auth, authorize("admin", "manager"), async (req, res) => {
  try {
    const year = Number(req.query.year) || new Date().getFullYear();
    const start = new Date(year, 0, 1);
    const end = new Date(year + 1, 0, 1);

    // ✅ Support BOTH schema styles:
    // - new style: dealStatus === "completed"
    // - old style: payment_status === "completed"
    const completed = await Sale.find({
      createdAt: { $gte: start, $lt: end },
      $or: [{ dealStatus: "completed" }, { payment_status: "completed" }],
    });

    const monthly = Array.from({ length: 12 }, (_, i) => ({
      month: i + 1,
      revenue: 0,
      count: 0,
      avgSaleValue: 0,
    }));

    completed.forEach((s) => {
      const m = new Date(s.createdAt).getMonth(); // 0-11

      // ✅ revenue fallback: finalPrice -> quotedPrice -> price
      const revenue = Number(
        s.finalPrice ?? s.quotedPrice ?? s.price ?? 0
      );

      monthly[m].revenue += revenue;
      monthly[m].count += 1;
    });

    monthly.forEach((m) => {
      m.avgSaleValue = m.count ? m.revenue / m.count : 0;
    });

    const totalRevenue = monthly.reduce((sum, m) => sum + m.revenue, 0);
    const totalSales = monthly.reduce((sum, m) => sum + m.count, 0);
    const monthsWithSales = monthly.filter((m) => m.count > 0).length;

    const avgMonthlyRevenue = monthsWithSales ? totalRevenue / monthsWithSales : 0;

    const bestMonth = monthly.reduce(
      (best, m) =>
        m.revenue > (best?.revenue ?? 0)
          ? { month: m.month, revenue: m.revenue }
          : best,
      null
    );

    res.json({ year, totalRevenue, totalSales, avgMonthlyRevenue, bestMonth, monthly });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

/**
 * ✅ GET ALL
 * GET /api/sales
 */
router.get("/", auth, authorize("admin", "manager"), async (req, res) => {
  try {
    const sales = await Sale.find()
      .populate("vehicle")
      .populate("customer") // (your schema says customer ref Lead, that's fine)
      .sort({ createdAt: -1 });

    res.json(sales);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

/**
 * ✅ ADD
 * Support BOTH:
 * - POST /api/sales
 * - POST /api/sales/add
 */
const createSaleHandler = async (req, res) => {
  try {
    const sale = await Sale.create(req.body);

    // ✅ completed check supports both schemas
    const isCompleted =
      sale.dealStatus === "completed" || sale.payment_status === "completed";

    if (isCompleted && sale.vehicle) {
      await Vehicle.findByIdAndUpdate(sale.vehicle, { status: "sold" });
    }

    res.status(201).json(sale);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
};

router.post("/", auth, authorize("admin", "manager"), createSaleHandler);
router.post("/add", auth, authorize("admin", "manager"), createSaleHandler);

/**
 * ✅ GET ONE
 * GET /api/sales/:id
 */
router.get("/:id", auth, authorize("admin", "manager"), async (req, res) => {
  const { id } = req.params;
  if (!validateObjectId(id)) return res.status(400).json({ message: "Invalid sale ID" });

  try {
    const sale = await Sale.findById(id).populate("vehicle").populate("customer");
    if (!sale) return res.status(404).json({ message: "Sale not found" });

    res.json(sale);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

/**
 * ✅ UPDATE
 * PUT /api/sales/:id
 * - if becomes completed -> vehicle becomes sold
 */
router.put("/:id", auth, authorize("admin", "manager"), async (req, res) => {
  const { id } = req.params;
  if (!validateObjectId(id)) return res.status(400).json({ message: "Invalid sale ID" });

  try {
    const updated = await Sale.findByIdAndUpdate(id, req.body, {
      new: true,
      runValidators: true,
    });

    if (!updated) return res.status(404).json({ message: "Sale not found" });

    const isCompleted =
      updated.dealStatus === "completed" || updated.payment_status === "completed";

    if (isCompleted && updated.vehicle) {
      await Vehicle.findByIdAndUpdate(updated.vehicle, { status: "sold" });
    }

    res.json(updated);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

/**
 * ✅ DELETE
 * DELETE /api/sales/:id
 */
router.delete("/:id", auth, authorize("admin", "manager"), async (req, res) => {
  const { id } = req.params;
  if (!validateObjectId(id)) return res.status(400).json({ message: "Invalid sale ID" });

  try {
    const deleted = await Sale.findByIdAndDelete(id);
    if (!deleted) return res.status(404).json({ message: "Sale not found" });

    // OPTIONAL: if you delete a completed sale, you may want to free vehicle
    const wasCompleted =
      deleted.dealStatus === "completed" || deleted.payment_status === "completed";

    if (wasCompleted && deleted.vehicle) {
      await Vehicle.findByIdAndUpdate(deleted.vehicle, { status: "available" });
    }

    res.json({ message: "Sale deleted" });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

module.exports = router;
